export const handler = (input) => {
  const monitored = ['dscr', 'leverage', 'current_ratio'];
  if (input.covenant_threshold === 0) {
    return {
      adequate_headroom: false,
      headroom_pct: 0,
      recommendation: 'invalid_threshold_zero'
    };
  }
  const headroom = (input.base_case_value - input.covenant_threshold) / input.covenant_threshold;
  if (!monitored.includes(input.covenant_type)) {
    return {
      adequate_headroom: true,
      headroom_pct: headroom,
      recommendation: 'covenant_type_not_monitored_for_headroom'
    };
  }
  if (headroom < 0.10) {
    return {
      adequate_headroom: false,
      headroom_pct: headroom,
      recommendation: 'recalibrate_covenant_or_strengthen_structure'
    };
  }
  return {
    adequate_headroom: true,
    headroom_pct: headroom,
    recommendation: 'headroom_sufficient'
  };
};
